# Step 3: Parse JSON payloads into structured DataFrame
def parse_sensor_data(df, room_name):
    if len(df) == 0:
        return pd.DataFrame()
    records = []
    for _, row in df.iterrows():
        try:
            p = json.loads(row['payload']) if isinstance(row['payload'], str) else row['payload']
            records.append({
                'timestamp': pd.to_datetime(row['timestamp']),
                'room': room_name,
                'temperature': float(p.get('temperature', 0)),
                'humidity': float(p.get('humidity', 0)),
            })
        except: pass
    return pd.DataFrame(records).sort_values('timestamp')

