print(f'Parsed: Room A={len(room_a)}, Room B={len(room_b)}, Total={len(all_data)}')
if len(all_data) > 0:
    all_data.describe().round(2)

# Step 5: Comparison table
summary = []
for name, data in [('Room A', room_a), ('Room B', room_b)]:
    if len(data) > 0:
        summary.append({
            'Room': name,
            'Records': len(data),
            'Temp μ': f"{data['temperature'].mean():.1f}°C",
            'Temp σ': f"{data['temperature'].std():.2f}",
            'Temp Range': f"{data['temperature'].min():.1f} - {data['temperature'].max():.1f}",
            'Humid μ': f"{data['humidity'].mean():.1f}%",
            'Humid σ': f"{data['humidity'].std():.2f}",
            'Duration': f"{(data['timestamp'].max() - data['timestamp'].min()).total_seconds():.0f}s",
        })

if summary:
    pd.DataFrame(summary).style.set_properties(**{'text-align': 'center'})
else:
    print('No data. Run the Sensor Simulator first.')
